import{_ as e,o as i,c as l,a2 as r}from"./chunks/framework.LN3EJxkW.js";const p=JSON.parse('{"title":"后端与数据 Roadmap：从零基础到系统工程","description":"","frontmatter":{},"headers":[],"relativePath":"05-backend-data/roadmap.md","filePath":"05-backend-data/roadmap.md","lastUpdated":1784212366000}'),t={name:"05-backend-data/roadmap.md"};function o(n,a,h,d,u,c){return i(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="后端与数据-roadmap-从零基础到系统工程" tabindex="-1">后端与数据 Roadmap：从零基础到系统工程 <a class="header-anchor" href="#后端与数据-roadmap-从零基础到系统工程" aria-label="Permalink to &quot;后端与数据 Roadmap：从零基础到系统工程&quot;">​</a></h1><p>这是一条可以独立学习的后端与数据路线。先建立编程、命令行、网络和数据基础，再进入 Go 服务、数据库、缓存、消息、分布式和云原生；复杂架构必须由真实规模和故障需求推动。</p><h2 id="能力阶梯" tabindex="-1">能力阶梯 <a class="header-anchor" href="#能力阶梯" aria-label="Permalink to &quot;能力阶梯&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>能力目标</th><th>代表产出</th></tr></thead><tbody><tr><td>入门</td><td>会编程、使用命令行和理解请求/数据</td><td>CLI 与简单 HTTP 服务</td></tr><tr><td>初级</td><td>能构建带数据库的可靠 API</td><td>CRUD、认证、测试和部署</td></tr><tr><td>中级</td><td>能处理缓存、异步、文件与搜索</td><td>企业任务或文件系统</td></tr><tr><td>高级</td><td>能处理分布式故障、可观测性和交付</td><td>分布式任务系统</td></tr><tr><td>专项</td><td>能做领域建模、数据平台或基础设施</td><td>企业级综合平台</td></tr></tbody></table><hr><h2 id="阶段零-编程与计算机基础" tabindex="-1">阶段零：编程与计算机基础 <a class="header-anchor" href="#阶段零-编程与计算机基础" aria-label="Permalink to &quot;阶段零：编程与计算机基础&quot;">​</a></h2><h3 id="编程入门" tabindex="-1">编程入门 <a class="header-anchor" href="#编程入门" aria-label="Permalink to &quot;编程入门&quot;">​</a></h3><ul><li>[ ] 值、变量、类型、条件、循环、函数和错误。</li><li>[ ] Array/Slice、Map、Struct/Object、String 和基础文件处理。</li><li>[ ] 模块、包、依赖、输入输出和命令行参数。</li><li>[ ] 使用伪代码拆解问题，使用日志、断点和测试调试。</li><li>[ ] 先用 JavaScript 熟悉算法表达，再用 Go 重写关键题目并比较类型、内存和错误处理。</li></ul><h3 id="工具与环境" tabindex="-1">工具与环境 <a class="header-anchor" href="#工具与环境" aria-label="Permalink to &quot;工具与环境&quot;">​</a></h3><ul><li>[ ] 文件、目录、路径、权限、进程和环境变量。</li><li>[ ] 终端与 Shell 基础，Git 的提交、分支和远端协作。</li><li>[ ] 编辑器、格式化、静态检查、测试和调试器。</li><li>[ ] 二进制、十六进制、字符编码、时间和时区基础。</li><li>[ ] CPU、内存、磁盘和网络分别负责什么。</li></ul><h3 id="服务与数据入门" tabindex="-1">服务与数据入门 <a class="header-anchor" href="#服务与数据入门" aria-label="Permalink to &quot;服务与数据入门&quot;">​</a></h3><ul><li>[ ] 客户端、服务器、进程、端口、域名和 DNS。</li><li>[ ] HTTP 请求/响应、方法、状态码、Header、JSON 和 Cookie。</li><li>[ ] 数据库、表、行、列、主键、查询和事务的直觉。</li><li>[ ] 同步、异步、并发、并行和队列的基本区别。</li><li>[ ] 本地运行一个服务，使用 <code>curl</code> 请求并查看日志。</li></ul><p>必做：命令行 Todo、读取 JSON/CSV 的统计工具、内存 CRUD HTTP API，并为核心逻辑编写测试。</p><p>验收：能从空目录创建、运行、调试和提交程序；能解释一次 API 请求如何到达服务并返回数据。</p><hr><h2 id="阶段一-数据结构与算法" tabindex="-1">阶段一：数据结构与算法 <a class="header-anchor" href="#阶段一-数据结构与算法" aria-label="Permalink to &quot;阶段一：数据结构与算法&quot;">​</a></h2><ul><li>[ ] 复杂度、数组、链表、栈、队列、双端队列。</li><li>[ ] 哈希表、冲突、扩容、负载因子。</li><li>[ ] 二叉树、搜索树、堆、Trie、B+Tree 基础。</li><li>[ ] 图、DFS、BFS、拓扑排序、最短路径、并查集。</li><li>[ ] 二分、快速、归并、稳定排序和外部排序基础。</li><li>[ ] 双指针、滑动窗口、分治、贪心、回溯和动态规划。</li></ul><p>必做：LRU Cache、任务依赖调度器、Token Bucket 限流器、Top-K、简化 HashMap。</p><p>验收：能根据数据规模、操作频率和内存约束选择数据结构，不需要追求算法竞赛水平。</p><hr><h2 id="阶段二-go" tabindex="-1">阶段二：Go <a class="header-anchor" href="#阶段二-go" aria-label="Permalink to &quot;阶段二：Go&quot;">​</a></h2><h3 id="语言" tabindex="-1">语言 <a class="header-anchor" href="#语言" aria-label="Permalink to &quot;语言&quot;">​</a></h3><ul><li>[ ] Slice、Map、Struct、Interface、Pointer、Error、Package、Module、Generic。</li><li>[ ] Error Wrapping、业务错误、系统错误、可重试错误。</li></ul><h3 id="并发" tabindex="-1">并发 <a class="header-anchor" href="#并发" aria-label="Permalink to &quot;并发&quot;">​</a></h3><ul><li>[ ] Goroutine、Channel、Select、Context。</li><li>[ ] Mutex、RWMutex、WaitGroup、Atomic。</li><li>[ ] Worker Pool、并发限制、优雅停止。</li><li>[ ] Race Condition、Deadlock、Goroutine Leak。</li></ul><h3 id="工具" tabindex="-1">工具 <a class="header-anchor" href="#工具" aria-label="Permalink to &quot;工具&quot;">​</a></h3><ul><li>[ ] Test、Table-driven Test、Benchmark。</li><li>[ ] Race Detector、pprof、trace、vet、Staticcheck、Delve。</li></ul><p>必做：并发下载器、Worker Pool、优雅退出 HTTP 服务、CPU/Memory Profile 报告。</p><p>验收：能够编写可靠 Go 服务，正确处理取消、超时、竞争、错误和性能问题。</p><hr><h2 id="阶段三-linux、操作系统和网络" tabindex="-1">阶段三：Linux、操作系统和网络 <a class="header-anchor" href="#阶段三-linux、操作系统和网络" aria-label="Permalink to &quot;阶段三：Linux、操作系统和网络&quot;">​</a></h2><h3 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h3><ul><li>[ ] 文件、权限、用户、进程、Signal、Pipe、Socket、Systemd。</li><li>[ ] ps、top、htop、lsof、ss、curl、grep、awk、sed。</li><li>[ ] CPU、内存、磁盘、网络和日志排查。</li></ul><h3 id="操作系统" tabindex="-1">操作系统 <a class="header-anchor" href="#操作系统" aria-label="Permalink to &quot;操作系统&quot;">​</a></h3><ul><li>[ ] 进程、线程、用户态、内核态、系统调用。</li><li>[ ] 虚拟内存、Page、Stack、Heap、上下文切换。</li><li>[ ] File Descriptor、阻塞/非阻塞、I/O Multiplexing、epoll。</li><li>[ ] Lock、Deadlock、OOM、CPU 密集和 I/O 密集。</li></ul><h3 id="网络" tabindex="-1">网络 <a class="header-anchor" href="#网络" aria-label="Permalink to &quot;网络&quot;">​</a></h3><ul><li>[ ] DNS、TCP 握手、重传、滑动窗口、拥塞控制。</li><li>[ ] TLS、证书和 HTTPS。</li><li>[ ] HTTP/1.1、HTTP/2、HTTP/3、Keepalive、Connection Pool。</li><li>[ ] TIME_WAIT、反向代理、L4/L7 负载均衡。</li></ul><p>验收：服务不可访问时，能沿 DNS、网络、端口、进程、日志、依赖逐层排查。</p><hr><h2 id="阶段四-api-与服务" tabindex="-1">阶段四：API 与服务 <a class="header-anchor" href="#阶段四-api-与服务" aria-label="Permalink to &quot;阶段四：API 与服务&quot;">​</a></h2><ul><li>[ ] REST、RPC、gRPC、GraphQL、WebSocket、SSE、Webhook 的适用场景。</li><li>[ ] Resource、Method、Status Code、分页、筛选、排序、批量和版本。</li><li>[ ] 统一错误：输入、认证、权限、不存在、冲突、限流、系统和外部依赖。</li><li>[ ] Request ID、Logging、Recovery、Timeout、CORS、Rate Limit、Metrics、Trace。</li><li>[ ] Session、Cookie、JWT、OAuth2、OIDC、API Key。</li><li>[ ] RBAC、ABAC、资源权限、多租户和审计。</li><li>[ ] 幂等 Key、异步任务 API 和 OpenAPI。</li></ul><p>验收：API 不直接暴露数据库结构，错误可定位，权限由服务端控制，并具备测试、文档和监控。</p><hr><h2 id="阶段五-关系型数据库" tabindex="-1">阶段五：关系型数据库 <a class="header-anchor" href="#阶段五-关系型数据库" aria-label="Permalink to &quot;阶段五：关系型数据库&quot;">​</a></h2><h3 id="建模" tabindex="-1">建模 <a class="header-anchor" href="#建模" aria-label="Permalink to &quot;建模&quot;">​</a></h3><ul><li>[ ] 实体、关系、主键、外键、唯一约束。</li><li>[ ] 规范化、反规范化、审计字段、状态和历史。</li><li>[ ] 软删除的风险和多租户设计。</li></ul><h3 id="sql" tabindex="-1">SQL <a class="header-anchor" href="#sql" aria-label="Permalink to &quot;SQL&quot;">​</a></h3><ul><li>[ ] Join、Group By、Having、Subquery、CTE、Window Function。</li><li>[ ] 分页、游标分页、复杂筛选和 N+1。</li></ul><h3 id="索引" tabindex="-1">索引 <a class="header-anchor" href="#索引" aria-label="Permalink to &quot;索引&quot;">​</a></h3><ul><li>[ ] B+Tree、复合索引、最左前缀、覆盖索引。</li><li>[ ] Selectivity、Index Scan、Full Table Scan、Write Amplification。</li><li>[ ] Explain、Explain Analyze 和慢查询。</li></ul><h3 id="事务" tabindex="-1">事务 <a class="header-anchor" href="#事务" aria-label="Permalink to &quot;事务&quot;">​</a></h3><ul><li>[ ] ACID、隔离级别、MVCC、锁、死锁。</li><li>[ ] 乐观锁、悲观锁、唯一约束冲突和库存并发。</li><li>[ ] 避免长事务和事务中调用慢外部接口。</li></ul><h3 id="migration" tabindex="-1">Migration <a class="header-anchor" href="#migration" aria-label="Permalink to &quot;Migration&quot;">​</a></h3><ul><li>[ ] Schema、Data Migration、Expand and Contract。</li><li>[ ] 向后兼容、零停机、大表回填和回滚。</li><li>[ ] 备份、恢复、RPO 和 RTO。</li></ul><p>验收：能设计中等复杂度数据库、选择索引、分析慢查询、处理并发并完成安全迁移。</p><hr><h2 id="阶段六-redis-与缓存" tabindex="-1">阶段六：Redis 与缓存 <a class="header-anchor" href="#阶段六-redis-与缓存" aria-label="Permalink to &quot;阶段六：Redis 与缓存&quot;">​</a></h2><ul><li>[ ] String、Hash、List、Set、Sorted Set、Bitmap、HyperLogLog、Stream、Geo。</li><li>[ ] Cache Aside、Read Through、Write Through、多级缓存。</li><li>[ ] Key、TTL、命中率、随机过期。</li><li>[ ] 穿透、击穿、雪崩和热点 Key。</li><li>[ ] 缓存更新、删除、最终一致性和事件驱动失效。</li><li>[ ] 分布式锁：唯一值、Lua 释放、过期、续期、Fencing Token。</li></ul><p>原则：数据库是事实来源，缓存是派生数据。</p><p>验收：能说明什么时候不应该使用缓存，Redis 故障时系统可以降级。</p><hr><h2 id="阶段七-消息队列与异步任务" tabindex="-1">阶段七：消息队列与异步任务 <a class="header-anchor" href="#阶段七-消息队列与异步任务" aria-label="Permalink to &quot;阶段七：消息队列与异步任务&quot;">​</a></h2><ul><li>[ ] Producer、Consumer、Topic、Queue、Partition、Offset、Ack、Consumer Group。</li><li>[ ] At-most-once、At-least-once、重复、乱序、幂等 Consumer。</li><li>[ ] Retry、指数退避、Dead Letter Queue、Poison Message。</li><li>[ ] Schema 版本、消息积压、优先级和取消。</li><li>[ ] Transactional Outbox、最终一致性和补偿。</li></ul><p>验收：能处理重复消息、幂等、失败、死信、消息积压以及数据库与事件的一致性。</p><hr><h2 id="阶段八-搜索、对象存储与数据分析" tabindex="-1">阶段八：搜索、对象存储与数据分析 <a class="header-anchor" href="#阶段八-搜索、对象存储与数据分析" aria-label="Permalink to &quot;阶段八：搜索、对象存储与数据分析&quot;">​</a></h2><h3 id="搜索" tabindex="-1">搜索 <a class="header-anchor" href="#搜索" aria-label="Permalink to &quot;搜索&quot;">​</a></h3><ul><li>[ ] 倒排索引、Analyzer、Tokenizer、Mapping。</li><li>[ ] 全文、过滤、高亮、聚合、自动补全、Search After。</li><li>[ ] 数据库同步、更新和删除。</li><li>[ ] 搜索引擎不作为主数据库。</li></ul><h3 id="对象存储" tabindex="-1">对象存储 <a class="header-anchor" href="#对象存储" aria-label="Permalink to &quot;对象存储&quot;">​</a></h3><ul><li>[ ] S3、Bucket、Object、Key、Presigned URL。</li><li>[ ] Multipart Upload、断点续传、版本、生命周期、CDN、ETag。</li><li>[ ] 类型和内容校验、权限、病毒扫描和审计。</li></ul><h3 id="数据工程" tabindex="-1">数据工程 <a class="header-anchor" href="#数据工程" aria-label="Permalink to &quot;数据工程&quot;">​</a></h3><ul><li>[ ] OLTP、OLAP、ETL、ELT、CDC。</li><li>[ ] Warehouse、Lake、Batch、Streaming、Lineage、Data Quality。</li><li>[ ] 事实表、维度表、星型模型。</li><li>[ ] ClickHouse、dbt、Airflow、Kafka、Flink/Spark 的定位。</li><li>[ ] 漏斗、留存、错误率、性能和 AI 成本分析。</li></ul><hr><h2 id="阶段九-分布式系统" tabindex="-1">阶段九：分布式系统 <a class="header-anchor" href="#阶段九-分布式系统" aria-label="Permalink to &quot;阶段九：分布式系统&quot;">​</a></h2><p>演进顺序：单体、单机优化、垂直扩容、水平扩容、负载均衡、缓存、复制、消息、服务拆分、多区域。</p><h3 id="复制与分片" tabindex="-1">复制与分片 <a class="header-anchor" href="#复制与分片" aria-label="Permalink to &quot;复制与分片&quot;">​</a></h3><ul><li>[ ] Leader-Follower、Multi-Leader、Leaderless。</li><li>[ ] 同步/异步复制、复制延迟、Read-after-write、Failover。</li><li>[ ] Range、Hash、Directory Sharding、热点、扩容、跨分片、全局 ID。</li></ul><h3 id="一致性与共识" tabindex="-1">一致性与共识 <a class="header-anchor" href="#一致性与共识" aria-label="Permalink to &quot;一致性与共识&quot;">​</a></h3><ul><li>[ ] CAP 的正确理解。</li><li>[ ] Linearizability、Eventual Consistency、Read-your-writes、Quorum。</li><li>[ ] Raft 的 Leader Election、Log Replication、Term、Majority。</li></ul><h3 id="分布式事务" tabindex="-1">分布式事务 <a class="header-anchor" href="#分布式事务" aria-label="Permalink to &quot;分布式事务&quot;">​</a></h3><ul><li>[ ] 2PC、Saga、TCC、Outbox、Compensation、Idempotency。</li></ul><h3 id="故障模式" tabindex="-1">故障模式 <a class="header-anchor" href="#故障模式" aria-label="Permalink to &quot;故障模式&quot;">​</a></h3><ul><li>[ ] Network Partition、Partial Failure、Duplicate Request。</li><li>[ ] Retry Storm、Thundering Herd、Split Brain、Hot Key。</li><li>[ ] Backpressure、Cascading Failure。</li><li>[ ] Timeout、Backoff、Jitter、Circuit Breaker、Bulkhead、Load Shedding。</li></ul><p>验收：能处理部分失败和最终一致性，并知道什么时候不应该拆微服务或分库分表。</p><hr><h2 id="阶段十-系统设计" tabindex="-1">阶段十：系统设计 <a class="header-anchor" href="#阶段十-系统设计" aria-label="Permalink to &quot;阶段十：系统设计&quot;">​</a></h2><p>固定步骤：需求、非功能、规模估算、API、数据模型、高层架构、读写流程、扩展性、一致性、高可用、安全、可观测性、成本和 Trade-off。</p><p>每周设计：URL Shortener、File Storage、Notification、Task Queue、Order、Payment、Search、IM、Google Docs、Figma、ChatGPT、RAG Platform。</p><p>验收：先问需求和规模，不直接堆中间件；能说明方案适用范围和为什么不用更复杂方案。</p><hr><h2 id="阶段十一-docker、kubernetes、iac-与-ci-cd" tabindex="-1">阶段十一：Docker、Kubernetes、IaC 与 CI/CD <a class="header-anchor" href="#阶段十一-docker、kubernetes、iac-与-ci-cd" aria-label="Permalink to &quot;阶段十一：Docker、Kubernetes、IaC 与 CI/CD&quot;">​</a></h2><h3 id="docker" tabindex="-1">Docker <a class="header-anchor" href="#docker" aria-label="Permalink to &quot;Docker&quot;">​</a></h3><ul><li>[ ] Dockerfile、Layer、Multi-stage、非 Root、Volume、Network、Health Check、Signal、Compose、Registry、扫描。</li></ul><h3 id="kubernetes" tabindex="-1">Kubernetes <a class="header-anchor" href="#kubernetes" aria-label="Permalink to &quot;Kubernetes&quot;">​</a></h3><ul><li>[ ] Pod、Deployment、StatefulSet、Service、Ingress。</li><li>[ ] ConfigMap、Secret、Job、CronJob、PV/PVC。</li><li>[ ] Startup、Readiness、Liveness。</li><li>[ ] Rolling、Rollback、Canary、HPA、Helm。</li></ul><h3 id="terraform" tabindex="-1">Terraform <a class="header-anchor" href="#terraform" aria-label="Permalink to &quot;Terraform&quot;">​</a></h3><ul><li>[ ] Provider、Resource、State、Plan、Apply、Module、Remote State、Drift。</li></ul><h3 id="ci-cd" tabindex="-1">CI/CD <a class="header-anchor" href="#ci-cd" aria-label="Permalink to &quot;CI/CD&quot;">​</a></h3><ul><li>[ ] Lint、测试、构建、依赖和镜像扫描。</li><li>[ ] Registry、测试环境、Smoke Test、生产审批、灰度和回滚。</li><li>[ ] Commit、镜像、发布版本可追溯。</li></ul><p>验收：能将完整系统自动部署到集群，处理健康检查、扩容、灰度、回滚和基础设施变更。</p><hr><h2 id="阶段十二-可观测性、sre-与安全" tabindex="-1">阶段十二：可观测性、SRE 与安全 <a class="header-anchor" href="#阶段十二-可观测性、sre-与安全" aria-label="Permalink to &quot;阶段十二：可观测性、SRE 与安全&quot;">​</a></h2><h3 id="可观测性" tabindex="-1">可观测性 <a class="header-anchor" href="#可观测性" aria-label="Permalink to &quot;可观测性&quot;">​</a></h3><ul><li>[ ] 结构化日志、Request ID、Trace ID、版本和脱敏。</li><li>[ ] RED、USE、业务指标、分位数和告警。</li><li>[ ] OpenTelemetry、Prometheus、Grafana、Loki、Tempo/Jaeger。</li></ul><h3 id="sre" tabindex="-1">SRE <a class="header-anchor" href="#sre" aria-label="Permalink to &quot;SRE&quot;">​</a></h3><ul><li>[ ] SLI、SLO、SLA、Error Budget。</li><li>[ ] Timeout、Retry、Backoff、Jitter、熔断、限流、隔舱、降级。</li><li>[ ] Backup、Restore、RPO、RTO、故障演练和无责复盘。</li></ul><h3 id="安全" tabindex="-1">安全 <a class="header-anchor" href="#安全" aria-label="Permalink to &quot;安全&quot;">​</a></h3><ul><li>[ ] 密码哈希、Session、MFA、RBAC、ABAC、租户隔离。</li><li>[ ] SQL/Command Injection、Path Traversal、SSRF、IDOR、Replay、Mass Assignment。</li><li>[ ] 传输和静态加密、Secret 管理、日志脱敏、审计和数据删除。</li></ul><p>验收：能从告警定位到请求、服务、数据库或依赖；系统有明确 SLO、恢复方案和安全边界。</p><hr><h2 id="阶段十三-领域建模与架构" tabindex="-1">阶段十三：领域建模与架构 <a class="header-anchor" href="#阶段十三-领域建模与架构" aria-label="Permalink to &quot;阶段十三：领域建模与架构&quot;">​</a></h2><ul><li>[ ] Interface、Application、Domain、Infrastructure 分层。</li><li>[ ] Entity、Value Object、Aggregate、Repository、Domain Event。</li><li>[ ] Bounded Context 和统一业务语言。</li><li>[ ] 模块化单体优先于微服务。</li><li>[ ] 业务规则不堆在 Handler，数据库模型不等于领域模型。</li></ul><hr><h2 id="学习资源" tabindex="-1">学习资源 <a class="header-anchor" href="#学习资源" aria-label="Permalink to &quot;学习资源&quot;">​</a></h2><p>书籍：Learning Go、The Go Programming Language、100 Go Mistakes、How Linux Works、OSTEP、Computer Networking: A Top-Down Approach、高性能 MySQL、Database Internals、DDIA、Release It!、System Design Interview、Site Reliability Engineering、Kubernetes in Action、Terraform: Up &amp; Running。</p><p>网站：Go Blog、Go by Example、PostgreSQL Docs、Use The Index Luke、Percona、Cockroach Labs、ClickHouse、Jepsen、High Scalability、ByteByteGo、AWS Architecture、Cloudflare、Netflix Tech、Uber Engineering、Kubernetes Blog、CNCF、OpenTelemetry、Google SRE。</p><hr>',117)])])}const b=e(t,[["render",o]]);export{p as __pageData,b as default};
